import os
import threading
from datetime import datetime
from http.server import HTTPServer, BaseHTTPRequestHandler
import json
import urllib.parse


class LoggingUtility:
    def __init__(self, log_file='application.log', host='0.0.0.0', port=8080):
        self.log_file = log_file
        self.host = host
        self.port = port
        self.lock = threading.Lock()
        
        log_dir = os.path.dirname(self.log_file)
        if log_dir and not os.path.exists(log_dir):
            os.makedirs(log_dir)
    
    def write_log(self, service_name, level, message, metadata=None):
        timestamp = datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]
        
        log_entry = "[%s] [%s] [%s] %s" % (timestamp, service_name, level.upper(), message)
        
        if metadata:
            metadata_str = ' | '.join(['%s=%s' % (k, v) for k, v in metadata.items()])
            log_entry = "%s | %s" % (log_entry, metadata_str)
        
        log_entry = "%s\n" % log_entry
        
        with self.lock:
            with open(self.log_file, 'a') as f:
                f.write(log_entry)
    
    def start_server(self):
        utility = self
        
        class LogRequestHandler(BaseHTTPRequestHandler):
            def do_POST(self):
                if self.path == '/log':
                    content_length = int(self.headers.get('Content-Length', 0))
                    body = self.rfile.read(content_length)
                    
                    try:
                        data = json.loads(body.decode('utf-8'))
                        service_name = data.get('service', 'unknown')
                        level = data.get('level', 'info')
                        message = data.get('message', '')
                        metadata = data.get('metadata', {})
                        
                        utility.write_log(service_name, level, message, metadata)
                        
                        self.send_response(200)
                        self.send_header('Content-type', 'application/json')
                        self.end_headers()
                        self.wfile.write(json.dumps({'status': 'success'}).encode())
                    except Exception as e:
                        self.send_response(400)
                        self.send_header('Content-type', 'application/json')
                        self.end_headers()
                        self.wfile.write(json.dumps({'status': 'error', 'message': str(e)}).encode())
                else:
                    self.send_response(404)
                    self.end_headers()
            
            def do_GET(self):
                if self.path == '/health':
                    self.send_response(200)
                    self.send_header('Content-type', 'application/json')
                    self.end_headers()
                    self.wfile.write(json.dumps({'status': 'healthy'}).encode())
                else:
                    self.send_response(404)
                    self.end_headers()
            
            def log_message(self, format, *args):
                pass
        
        server = HTTPServer((self.host, self.port), LogRequestHandler)
        print("Centralized logging server started on %s:%d" % (self.host, self.port))
        print("Writing logs to: %s" % os.path.abspath(self.log_file))
        server.serve_forever()


if __name__ == '__main__':
    logger = LoggingUtility(log_file='logs/centralized.log', host='0.0.0.0', port=8080)
